  ('a0000000-0000-0000-0000-000000000353', 'd0000000-0000-0000-0000-000000000009', 'region', NULL, '부산 아기 사진 잘 찍어주는 스튜디오 추천해주세요! 100일 사진 찍으러 가려고요 📸', 3, 7, now() + interval '96 days'),
  ('a0000000-0000-0000-0000-000000000354', 'd0000000-0000-0000-0000-000000000082', 'region', NULL, '서울 예방접종 잘하는 소아과 아시는 분? 아기가 주사 맞고 안 울었으면 좋겠어요 ㅋㅋ', 42, 16, now() + interval '5 days'),
  ('a0000000-0000-0000-0000-000000000355', 'd0000000-0000-0000-0000-000000000071', 'birth_month', '2025-12', '2025-12생 맘 여기 모여요~! 우리 아기들 다들 잘 자라고 있죠? 요즘 뭐가 달라졌는지 공유해요! 😊', 4, 17, now() + interval '138 days'),
  ('a0000000-0000-0000-0000-000000000356', 'd0000000-0000-0000-0000-000000000065', 'region', NULL, '인천 산부인과 추천 부탁드려요. 첫 임신이라 병원 선택이 어려워요. 🏥', 46, 14, now() + interval '46 days'),
  ('a0000000-0000-0000-0000-000000000357', 'd0000000-0000-0000-0000-000000000068', 'general', NULL, '이유식 거부하던 아기가 바나나는 먹어요!! 바나나 만세! 🍌', 15, 20, now() + interval '91 days'),
  ('a0000000-0000-0000-0000-000000000358', 'd0000000-0000-0000-0000-000000000051', 'general', NULL, '배란테스트기 두 줄 떴어요!! 긴장되지만 이번 달은 좋은 예감이 들어요 🙏', 64, 13, now() + interval '63 days'),
  ('a0000000-0000-0000-0000-000000000359', 'd0000000-0000-0000-0000-000000000039', 'region', NULL, '부산 맘들~ 문화센터 수업 추천해주세요! 6개월 아기랑 다닐 수 있는 곳 찾고 있어요.', 57, 3, now() + interval '167 days'),
  ('a0000000-0000-0000-0000-000000000360', 'd0000000-0000-0000-0000-000000000052', 'general', NULL, '오늘 아기 데리고 첫 비행기 탔어요 ✈️ 이착륙 때 수유하니까 안 울었어요! 비행기 여행 팁 필요한 맘 있으면 물어보세요~', 38, 16, now() - interval '3 days'),
  ('a0000000-0000-0000-0000-000000000361', 'd0000000-0000-0000-0000-000000000011', 'birth_month', '2025-09', '2025-09생 아기 첫 치카! 실리콘 칫솔로 닦아줬는데 재밌어하네요 ㅎㅎ', 30, 21, now() + interval '145 days'),
  ('a0000000-0000-0000-0000-000000000362', 'd0000000-0000-0000-0000-000000000006', 'general', NULL, '아기 첫 발 디딤 👣 7개월부터 잡고 서더니 드디어 혼자 한 발! 순간 온 가족이 박수 치며 환호했어요 ㅋㅋ', 60, 19, now() + interval '12 days'),
  ('a0000000-0000-0000-0000-000000000363', 'd0000000-0000-0000-0000-000000000088', 'qna', NULL, '아기 낮잠을 거부해요 ㅠ 눈은 졸린데 안 자려고 버텨요. 낮잠 잘 재우는 팁?', 60, 18, now() + interval '9 days'),
  ('a0000000-0000-0000-0000-000000000364', 'd0000000-0000-0000-0000-000000000041', 'general', NULL, '아기 첫 발 디딤 👣 7개월부터 잡고 서더니 드디어 혼자 한 발! 순간 온 가족이 박수 치며 환호했어요 ㅋㅋ', 16, 19, now() - interval '102 days'),
  ('a0000000-0000-0000-0000-000000000365', 'd0000000-0000-0000-0000-000000000039', 'general', NULL, '첫째 재우고 둘째 먹이고... 투맘의 하루는 정신없지만 둘 다 잠든 밤이 제일 평화로워요 🌟', 18, 19, now() + interval '100 days'),
  ('a0000000-0000-0000-0000-000000000366', 'd0000000-0000-0000-0000-000000000043', 'general', NULL, '남편이 퇴근하고 아기 목욕 시키는 거 보면 너무 웃겨요 ㅋㅋ 하나도 안 능숙한데 아기가 아빠한테만 까르르 웃어요. 🛁', 50, 5, now() + interval '177 days'),
  ('a0000000-0000-0000-0000-000000000367', 'd0000000-0000-0000-0000-000000000065', 'region', NULL, '대구 아기 수영장 다니는 맘 계세요? 어떤 프로그램이 좋은지 궁금해요.', 25, 2, now() - interval '60 days'),
  ('a0000000-0000-0000-0000-000000000368', 'd0000000-0000-0000-0000-000000000078', 'region', NULL, '서울 키즈카페 추천! 넓고 깨끗하고 부모 쉴 공간도 있어요. 커피도 맛있고 ㅎㅎ', 64, 20, now() - interval '84 days'),
  ('a0000000-0000-0000-0000-000000000369', 'd0000000-0000-0000-0000-000000000058', 'birth_month', '2025-10', '2025-10생 아기 숟가락 혼자 잡아요! 반은 흘리지만 스스로 하려는 모습이 대견해요 💕', 25, 18, now() + interval '111 days'),
  ('a0000000-0000-0000-0000-000000000370', 'd0000000-0000-0000-0000-000000000075', 'region', NULL, '대구 맘들~ 문화센터 수업 추천해주세요! 6개월 아기랑 다닐 수 있는 곳 찾고 있어요.', 8, 20, now() - interval '64 days'),
  ('a0000000-0000-0000-0000-000000000371', 'd0000000-0000-0000-0000-000000000035', 'general', NULL, '드디어 통잠 성공!! 7시간 연속으로 잤어요!! 저도 같이 잤는데 아침에 개운함에 울 뻔 ㅋㅋ', 48, 21, now() - interval '100 days'),
  ('a0000000-0000-0000-0000-000000000372', 'd0000000-0000-0000-0000-000000000047', 'general', NULL, '아기 돌잔치 준비 중인데 잔치 대신 가족여행 가기로 했어요. 돌여행 다녀온 맘들 좋았던 곳 추천해주세요!', 3, 10, now() + interval '70 days'),
  ('a0000000-0000-0000-0000-000000000373', 'd0000000-0000-0000-0000-000000000017', 'general', NULL, '아기가 강아지 보고 "멍멍!" 했어요 ㅋㅋ 동물 소리 책 효과가 있었나봐요 🐕', 30, 15, now() + interval '132 days'),
  ('a0000000-0000-0000-0000-000000000374', 'd0000000-0000-0000-0000-000000000014', 'general', NULL, '아기가 까꿍 놀이에 반응하기 시작했어요! 제가 숨으면 두리번거리다가 찾으면 빵 터져요 ㅋㅋ', 25, 18, now() - interval '154 days'),
  ('a0000000-0000-0000-0000-000000000375', 'd0000000-0000-0000-0000-000000000050', 'general', NULL, '입덧 끝나니 세상이 달라 보여요! 3개월 동안 물만 먹었는데 오늘 치킨 먹었어요 🍗', 29, 13, now() + interval '144 days'),
  ('a0000000-0000-0000-0000-000000000376', 'd0000000-0000-0000-0000-000000000074', 'birth_month', '2025-12', '2025-12생 아기 "맘마" "빠빠" 말해요! 돌 전에 말 시작하니 대화가 되는 느낌? ㅋㅋ', 46, 13, now() - interval '69 days'),
  ('a0000000-0000-0000-0000-000000000377', 'd0000000-0000-0000-0000-000000000064', 'general', NULL, '어제 밤 아기가 잠꼬대로 "맘마" 했어요 ㅋㅋ 꿈에서도 밥 생각하는 우리 아기...', 13, 14, now() - interval '77 days'),
  ('a0000000-0000-0000-0000-000000000378', 'd0000000-0000-0000-0000-000000000010', 'general', NULL, '쌍둥이 임신 확인! 😱 기쁘면서도 걱정이... 쌍둥이 맘들 조언 부탁드려요.', 63, 8, now() + interval '127 days'),
  ('a0000000-0000-0000-0000-000000000379', 'd0000000-0000-0000-0000-000000000059', 'general', NULL, '오늘 아기가 처음으로 컵으로 물 마셨어요! 반은 흘렸지만 대견해요 ㅋㅋ', 22, 1, now() + interval '86 days'),
  ('a0000000-0000-0000-0000-000000000380', 'd0000000-0000-0000-0000-000000000043', 'birth_month', '2025-12', '2025-12생 맘들 아기 몸무게 어때요? 우리 8kg인데 큰 건지 작은 건지 궁금해요.', 30, 21, now() + interval '35 days'),
  ('a0000000-0000-0000-0000-000000000381', 'd0000000-0000-0000-0000-000000000078', 'qna', NULL, '태교 음악 뭐 들으세요? 클래식이 좋다고 하는데 저는 발라드가 더 편해요 🎵', 15, 16, now() - interval '102 days'),
  ('a0000000-0000-0000-0000-000000000382', 'd0000000-0000-0000-0000-000000000038', 'region', NULL, '용인 베이비 마사지 배울 수 있는 곳 아시나요? 아기 배 마사지 해주면 잠을 잘 잔다고 해서요.', 43, 16, now() + interval '63 days'),
  ('a0000000-0000-0000-0000-000000000383', 'd0000000-0000-0000-0000-000000000036', 'region', NULL, '울산 공원에서 소풍 모임 할 건데 참여할 맘? 도시락 각자 싸오고 아기들끼리 놀아요 🧺', 28, 12, now() - interval '145 days'),
  ('a0000000-0000-0000-0000-000000000384', 'd0000000-0000-0000-0000-000000000070', 'general', NULL, '아기 돌 지나니 말이 폭발적으로 늘어요! 어제는 "주세요"를 처음 했어요.', 52, 18, now() - interval '119 days'),
  ('a0000000-0000-0000-0000-000000000385', 'd0000000-0000-0000-0000-000000000057', 'region', NULL, '청주 아기랑 가기 좋은 카페 발견! 키즈존도 넓고 이유식 데워주시고 수유실도 있어요 🍊', 56, 3, now() + interval '105 days'),
  ('a0000000-0000-0000-0000-000000000386', 'd0000000-0000-0000-0000-000000000082', 'general', NULL, '오늘 아기가 처음으로 컵으로 물 마셨어요! 반은 흘렸지만 대견해요 ㅋㅋ', 19, 22, now() - interval '109 days'),
  ('a0000000-0000-0000-0000-000000000387', 'd0000000-0000-0000-0000-000000000010', 'birth_month', '2026-04', '2026-04생 맘들 체중 궁금해요! 우리 9.5kg인데 먹는 양에 비해 안 느는 것 같아서요.', 41, 16, now() + interval '137 days'),
  ('a0000000-0000-0000-0000-000000000388', 'd0000000-0000-0000-0000-000000000054', 'birth_month', '2026-05', '2026-05생 맘들 어린이집 보내셨어요? 아직 이르려나... 고민 중이에요.', 53, 12, now() + interval '138 days'),
  ('a0000000-0000-0000-0000-000000000389', 'd0000000-0000-0000-0000-000000000011', 'general', NULL, '아기 첫 뒤집기 성공! 🎉 거실에서 나만 보고 있었는데 갑자기 되더라구요. 남편한테 영상 보여줬더니 자기도 보고 싶었다고 ㅠㅠ', 18, 22, now() + interval '43 days'),
  ('a0000000-0000-0000-0000-000000000390', 'd0000000-0000-0000-0000-000000000073', 'qna', NULL, '모유 저장 방법 알려주세요! 냉동하면 얼마나 보관 가능해요? 해동은 어떻게?', 46, 21, now() - interval '85 days'),
  ('a0000000-0000-0000-0000-000000000391', 'd0000000-0000-0000-0000-000000000056', 'general', NULL, '배란테스트기 두 줄 떴어요!! 긴장되지만 이번 달은 좋은 예감이 들어요 🙏', 9, 9, now() - interval '133 days'),
  ('a0000000-0000-0000-0000-000000000392', 'd0000000-0000-0000-0000-000000000058', 'general', NULL, '엄마 몸이 많이 힘든데 아기 웃음 소리 들으면 충전 100% 돼요. 이 감정이 모성인가 봐요 💪', 32, 22, now() + interval '129 days'),
  ('a0000000-0000-0000-0000-000000000393', 'd0000000-0000-0000-0000-000000000045', 'qna', NULL, '아기 땀띠가 심해요. 목이랑 겨드랑이에 발갛게 올라왔는데 어떻게 해요? 😥', 33, 4, now() - interval '22 days'),
  ('a0000000-0000-0000-0000-000000000394', 'd0000000-0000-0000-0000-000000000094', 'general', NULL, '카페에서 아기가 조용하게 앉아있길래 뭐 하나 봤더니 휴지를 다 뜯고 있었어요 ㅋㅋ 창의력이라고 하겠습니다...', 22, 11, now() + interval '53 days'),
  ('a0000000-0000-0000-0000-000000000395', 'd0000000-0000-0000-0000-000000000062', 'general', NULL, '드디어 통잠 성공!! 7시간 연속으로 잤어요!! 저도 같이 잤는데 아침에 개운함에 울 뻔 ㅋㅋ', 9, 15, now() + interval '116 days'),
  ('a0000000-0000-0000-0000-000000000396', 'd0000000-0000-0000-0000-000000000009', 'general', NULL, '아기 돌잔치 준비 중인데 잔치 대신 가족여행 가기로 했어요. 돌여행 다녀온 맘들 좋았던 곳 추천해주세요!', 54, 4, now() - interval '88 days'),
  ('a0000000-0000-0000-0000-000000000397', 'd0000000-0000-0000-0000-000000000087', 'region', NULL, '대전 아기 수영장 다니는 맘 계세요? 어떤 프로그램이 좋은지 궁금해요.', 62, 8, now() + interval '142 days'),
  ('a0000000-0000-0000-0000-000000000398', 'd0000000-0000-0000-0000-000000000072', 'birth_month', '2025-10', '2025-10생 맘들 분유 뭐 먹이세요? 우리 애가 지금 먹는 분유에 배가 더부룩한 것 같아서 바꿔볼까 해요.', 32, 8, now() + interval '162 days'),
  ('a0000000-0000-0000-0000-000000000399', 'd0000000-0000-0000-0000-000000000082', 'region', NULL, '전주 공원에서 소풍 모임 할 건데 참여할 맘? 도시락 각자 싸오고 아기들끼리 놀아요 🧺', 28, 1, now() + interval '51 days'),
  ('a0000000-0000-0000-0000-000000000400', 'd0000000-0000-0000-0000-000000000055', 'general', NULL, '아기 돌잔치 준비 중인데 잔치 대신 가족여행 가기로 했어요. 돌여행 다녀온 맘들 좋았던 곳 추천해주세요!', 48, 7, now() - interval '17 days')
INSERT INTO posts (id, user_id, board_type, board_key, content, like_count, comment_count, created_at) VALUES
  ('a0000000-0000-0000-0000-000000000401', 'd0000000-0000-0000-0000-000000000069', 'general', NULL, '아기랑 첫 놀이동산! 회전목마 탔는데 표정이 멍... ㅋㅋ 좋은 건지 무서운 건지 모르겠어요 🎠', 23, 7, now() + interval '68 days'),
  ('a0000000-0000-0000-0000-000000000402', 'd0000000-0000-0000-0000-000000000068', 'qna', NULL, '임신 16주차인데 태동을 아직 못 느껴요. 초산이라 잘 모르겠어요 😢', 23, 20, now() - interval '101 days'),
  ('a0000000-0000-0000-0000-000000000403', 'd0000000-0000-0000-0000-000000000015', 'general', NULL, '오늘 처음으로 아기가 고개를 돌려서 저를 찾았어요. "엄마 어디?" 하는 표정에 심장 녹았습니다 ❤️', 57, 15, now() + interval '173 days'),
  ('a0000000-0000-0000-0000-000000000404', 'd0000000-0000-0000-0000-000000000079', 'birth_month', '2025-12', '2025-12생 아기 첫 이가 나왔어요! 아래 앞니인데 웃을 때 보이는 게 너무 귀여워요 😄', 46, 5, now() - interval '62 days'),
  ('a0000000-0000-0000-0000-000000000405', 'd0000000-0000-0000-0000-000000000024', 'general', NULL, '출산 후 처음으로 예전 청바지 입었어요! 3개월 걸렸지만 다시 맞다니 ㅠㅠ 조금씩 나를 되찾아가는 기분.', 12, 17, now() - interval '153 days'),
  ('a0000000-0000-0000-0000-000000000406', 'd0000000-0000-0000-0000-000000000074', 'general', NULL, '시어머니가 이유식 만들어오셨는데 정성이 가득... 우리 아기가 할머니 이유식이 더 잘 먹어요 ㅋㅋ 비밀이에요 🤫', 14, 16, now() + interval '178 days'),
  ('a0000000-0000-0000-0000-000000000407', 'd0000000-0000-0000-0000-000000000072', 'general', NULL, '제주도 한 달 살기 중인데 아기랑 해변 산책하니 힐링 그 자체에요 🌊 바람 소리에 아기가 까르르 웃어요.', 21, 5, now() - interval '116 days'),
  ('a0000000-0000-0000-0000-000000000408', 'd0000000-0000-0000-0000-000000000046', 'qna', NULL, '아기 6개월인데 밤에 아직 3번씩 깨요. 이게 정상인 건가요? 수면교육 해야 할까요?', 34, 5, now() - interval '99 days'),
  ('a0000000-0000-0000-0000-000000000409', 'd0000000-0000-0000-0000-000000000065', 'region', NULL, '청주 놀이터 좋은 곳 아시는 맘 계세요? 바닥이 폭신하고 그늘 있는 곳 찾고 있어요.', 29, 22, now() + interval '114 days'),
  ('a0000000-0000-0000-0000-000000000410', 'd0000000-0000-0000-0000-000000000011', 'birth_month', '2025-11', '2025-11생 첫 돌 케이크 어디서 주문했어요? 무설탕 케이크 찾고 있어요~', 53, 8, now() - interval '71 days'),
  ('a0000000-0000-0000-0000-000000000411', 'd0000000-0000-0000-0000-000000000037', 'general', NULL, '오늘 소아과에서 발달검사 했는데 "잘 크고 있어요"라는 말에 눈물이 핑... 맘들 다 잘하고 있는 거예요 💪', 32, 19, now() + interval '127 days'),
  ('a0000000-0000-0000-0000-000000000412', 'd0000000-0000-0000-0000-000000000066', 'general', NULL, '첫째 재우고 둘째 먹이고... 투맘의 하루는 정신없지만 둘 다 잠든 밤이 제일 평화로워요 🌟', 10, 9, now() + interval '94 days'),
  ('a0000000-0000-0000-0000-000000000413', 'd0000000-0000-0000-0000-000000000097', 'general', NULL, '아기 돌잔치 준비 중인데 잔치 대신 가족여행 가기로 했어요. 돌여행 다녀온 맘들 좋았던 곳 추천해주세요!', 49, 15, now() + interval '109 days'),
  ('a0000000-0000-0000-0000-000000000414', 'd0000000-0000-0000-0000-000000000095', 'region', NULL, '전주 키즈카페 추천! 넓고 깨끗하고 부모 쉴 공간도 있어요. 커피도 맛있고 ㅎㅎ', 51, 8, now() - interval '9 days'),
  ('a0000000-0000-0000-0000-000000000415', 'd0000000-0000-0000-0000-000000000045', 'qna', NULL, '아기 아토피 있는 맘들 보습제 뭐 쓰세요? 병원 로션은 너무 비싸요...', 8, 15, now() + interval '31 days'),
  ('a0000000-0000-0000-0000-000000000416', 'd0000000-0000-0000-0000-000000000031', 'general', NULL, '오늘 유모차 타고 동네 한 바퀴 돌았는데 이웃 할머니들이 아기 보고 예쁘다고 해주셔요. 기분 좋은 하루!', 50, 19, now() + interval '157 days'),
  ('a0000000-0000-0000-0000-000000000417', 'd0000000-0000-0000-0000-000000000022', 'birth_month', '2026-05', '2026-05생 예정맘인데 곧 만나네요! 출산가방 다 쌌는데 혹시 빠진 거 없는지 봐주세요 🥹', 53, 7, now() + interval '16 days'),
  ('a0000000-0000-0000-0000-000000000418', 'd0000000-0000-0000-0000-000000000069', 'general', NULL, '육아는 체력이라는 말이 진짜였어요. 밤새 안 자는 아기랑 씨름하다 보면 새벽이에요 ㅠ', 37, 6, now() - interval '75 days'),
  ('a0000000-0000-0000-0000-000000000419', 'd0000000-0000-0000-0000-000000000074', 'general', NULL, '친정엄마가 미역국 끓여오셨는데 울면서 먹었어요. 출산 후 처음으로 엄마의 마음을 이해했어요 💕', 57, 17, now() + interval '174 days'),
  ('a0000000-0000-0000-0000-000000000420', 'd0000000-0000-0000-0000-000000000018', 'qna', NULL, '임신 중 카페인 얼마까지 괜찮아요? 커피 한 잔도 안 되나요?', 53, 14, now() + interval '71 days'),
  ('a0000000-0000-0000-0000-000000000421', 'd0000000-0000-0000-0000-000000000084', 'general', NULL, '입덧 끝나니 세상이 달라 보여요! 3개월 동안 물만 먹었는데 오늘 치킨 먹었어요 🍗', 58, 5, now() - interval '83 days'),
  ('a0000000-0000-0000-0000-000000000422', 'd0000000-0000-0000-0000-000000000098', 'region', NULL, '성남 아기띠 체험 가능한 매장 아시나요? 직접 메보고 사고 싶어요.', 28, 16, now() - interval '162 days'),
  ('a0000000-0000-0000-0000-000000000423', 'd0000000-0000-0000-0000-000000000049', 'birth_month', '2026-07', '2026-07생 예정맘인데 곧 만나네요! 출산가방 다 쌌는데 혹시 빠진 거 없는지 봐주세요 🥹', 43, 3, now() + interval '72 days'),
  ('a0000000-0000-0000-0000-000000000424', 'd0000000-0000-0000-0000-000000000059', 'qna', NULL, '출산 예정일 지났는데 아기가 안 나와요 ㅠㅠ 유도분만 해야 하나요?', 23, 19, now() - interval '24 days'),
  ('a0000000-0000-0000-0000-000000000425', 'd0000000-0000-0000-0000-000000000059', 'birth_month', '2026-02', '2026-02생 아기 돌잡이 뭐 잡았어요? 우리는 마이크 잡았어요! 🎤 미래의 가수인가 ㅋㅋ', 47, 12, now() + interval '137 days'),
  ('a0000000-0000-0000-0000-000000000426', 'd0000000-0000-0000-0000-000000000055', 'region', NULL, '용인 예방접종 잘하는 소아과 아시는 분? 아기가 주사 맞고 안 울었으면 좋겠어요 ㅋㅋ', 34, 9, now() - interval '73 days'),
  ('a0000000-0000-0000-0000-000000000427', 'd0000000-0000-0000-0000-000000000074', 'general', NULL, '제주도 한 달 살기 중인데 아기랑 해변 산책하니 힐링 그 자체에요 🌊 바람 소리에 아기가 까르르 웃어요.', 57, 16, now() + interval '175 days'),
  ('a0000000-0000-0000-0000-000000000428', 'd0000000-0000-0000-0000-000000000006', 'general', NULL, '이유식 시간이 전쟁터에요 ㅋㅋ 한 숟갈 먹이는데 30분... 바닥은 전쟁 후 같고 아기 얼굴은 고구마 범벅 😂', 53, 15, now() - interval '41 days'),
  ('a0000000-0000-0000-0000-000000000429', 'd0000000-0000-0000-0000-000000000059', 'general', NULL, '아기 목욕 시간이 제일 좋아요. 물 만나면 발차기하고 웃고... 근데 꺼내면 세상 끝난 것처럼 울어요 ㅋㅋ', 64, 14, now() - interval '177 days'),
  ('a0000000-0000-0000-0000-000000000430', 'd0000000-0000-0000-0000-000000000084', 'general', NULL, '아기 백일인데 남편이 몰래 케이크 준비했어요 🎂 촛불 보고 아기가 손뼉 치는데... 💕', 58, 9, now() - interval '93 days'),
  ('a0000000-0000-0000-0000-000000000431', 'd0000000-0000-0000-0000-000000000011', 'general', NULL, '아기랑 같이 낮잠 자는 게 세상에서 제일 행복한 시간이에요. 따뜻한 온기가 느껴져요.', 60, 21, now() - interval '102 days'),
  ('a0000000-0000-0000-0000-000000000432', 'd0000000-0000-0000-0000-000000000093', 'region', NULL, '서울 맘들 아기 옷 교환 모임 만들면 참여하실 분? 빠르게 크는 아기옷 서로 나누면 좋을 것 같아요!', 17, 14, now() + interval '25 days'),
  ('a0000000-0000-0000-0000-000000000433', 'd0000000-0000-0000-0000-000000000062', 'general', NULL, '새벽 4시 수유하면서 보는 하늘이 진짜 예뻐요. 힘들지만 아기 얼굴 보면 다 녹아요 ㅎㅎ 같은 시간에 깨어있는 맘들 계시면 손 흔들어요~ 🌙', 40, 8, now() + interval '114 days'),
  ('a0000000-0000-0000-0000-000000000434', 'd0000000-0000-0000-0000-000000000002', 'region', NULL, '광주 맘들 어디서 만나세요? 육아 수다 떨 친구가 필요해요 ㅋㅋ', 55, 4, now() + interval '109 days'),
  ('a0000000-0000-0000-0000-000000000435', 'd0000000-0000-0000-0000-000000000010', 'general', NULL, '오늘 처음으로 아기가 고개를 돌려서 저를 찾았어요. "엄마 어디?" 하는 표정에 심장 녹았습니다 ❤️', 8, 4, now() - interval '95 days'),
  ('a0000000-0000-0000-0000-000000000436', 'd0000000-0000-0000-0000-000000000018', 'general', NULL, '오늘 아기가 거울 보고 자기 모습에 깜짝 놀랐어요 ㅋㅋ 거울 속 아기한테 손도 뻗고 박치기도 하고...', 55, 5, now() + interval '174 days'),
  ('a0000000-0000-0000-0000-000000000437', 'd0000000-0000-0000-0000-000000000009', 'birth_month', '2026-01', '2026-01생 아기 손 빨기 시작했는데 정상인가요? 공갈젖꼭지 물려야 하나 고민이에요.', 3, 20, now() + interval '113 days'),
  ('a0000000-0000-0000-0000-000000000438', 'd0000000-0000-0000-0000-000000000028', 'birth_month', '2025-11', '2025-11생 맘들 뒤집기 시작했나요? 우리 애는 옆으로만 가요 ㅋㅋ 통통해서 그런가...', 12, 14, now() + interval '114 days'),
  ('a0000000-0000-0000-0000-000000000439', 'd0000000-0000-0000-0000-000000000013', 'general', NULL, '오늘 유모차 타고 동네 한 바퀴 돌았는데 이웃 할머니들이 아기 보고 예쁘다고 해주셔요. 기분 좋은 하루!', 10, 19, now() + interval '90 days'),
  ('a0000000-0000-0000-0000-000000000440', 'd0000000-0000-0000-0000-000000000041', 'region', NULL, '포항 아기 사진 잘 찍어주는 스튜디오 추천해주세요! 100일 사진 찍으러 가려고요 📸', 18, 9, now() + interval '64 days'),
  ('a0000000-0000-0000-0000-000000000441', 'd0000000-0000-0000-0000-000000000077', 'region', NULL, '고양 맘들 아기 옷 교환 모임 만들면 참여하실 분? 빠르게 크는 아기옷 서로 나누면 좋을 것 같아요!', 21, 1, now() + interval '169 days'),
  ('a0000000-0000-0000-0000-000000000442', 'd0000000-0000-0000-0000-000000000067', 'birth_month', '2025-11', '2025-11생 아기 하이파이브 배웠어요! "하이~" 하면서 손뼉 치는데 세상 귀여워요 🤗', 15, 13, now() - interval '14 days'),
  ('a0000000-0000-0000-0000-000000000443', 'd0000000-0000-0000-0000-000000000050', 'general', NULL, '새벽 4시 수유하면서 보는 하늘이 진짜 예뻐요. 힘들지만 아기 얼굴 보면 다 녹아요 ㅎㅎ 같은 시간에 깨어있는 맘들 계시면 손 흔들어요~ 🌙', 34, 21, now() + interval '136 days'),
  ('a0000000-0000-0000-0000-000000000444', 'd0000000-0000-0000-0000-000000000047', 'qna', NULL, '워킹맘인데 짧은 시간이라도 질 높은 놀이 방법 있을까요? 죄책감이 커요...', 11, 13, now() + interval '146 days'),
  ('a0000000-0000-0000-0000-000000000445', 'd0000000-0000-0000-0000-000000000047', 'birth_month', '2025-08', '2025-08 예정인데 여름 출산이라 땀띠 걱정... 여름 신생아 케어 팁 부탁해요!', 14, 16, now() + interval '19 days'),
  ('a0000000-0000-0000-0000-000000000446', 'd0000000-0000-0000-0000-000000000009', 'general', NULL, '아기가 분유병을 혼자 잡고 먹어요! 독립심이 자라나는 건가요? ㅋㅋ 뿌듯하면서 쓸쓸 ㅎ', 16, 2, now() + interval '102 days'),
  ('a0000000-0000-0000-0000-000000000447', 'd0000000-0000-0000-0000-000000000037', 'birth_month', '2025-09', '2025-09생 맘들 어린이집 보내셨어요? 아직 이르려나... 고민 중이에요.', 35, 14, now() + interval '103 days'),
  ('a0000000-0000-0000-0000-000000000448', 'd0000000-0000-0000-0000-000000000069', 'birth_month', '2026-04', '2026-04생 아기 돌잡이 뭐 잡았어요? 우리는 마이크 잡았어요! 🎤 미래의 가수인가 ㅋㅋ', 12, 9, now() - interval '21 days'),
  ('a0000000-0000-0000-0000-000000000449', 'd0000000-0000-0000-0000-000000000020', 'birth_month', '2026-06', '2026-06생 맘들 어린이집 보내셨어요? 아직 이르려나... 고민 중이에요.', 28, 19, now() + interval '167 days'),
  ('a0000000-0000-0000-0000-000000000450', 'd0000000-0000-0000-0000-000000000009', 'general', NULL, '아기가 혼자 서서 박수까지! 발달이 한 번에 오는 것 같아요. 어제까지 못 했는데 오늘 갑자기!', 30, 8, now() - interval '23 days')
INSERT INTO posts (id, user_id, board_type, board_key, content, like_count, comment_count, created_at) VALUES
  ('a0000000-0000-0000-0000-000000000451', 'd0000000-0000-0000-0000-000000000015', 'birth_month', '2026-07', '2026-07생 맘들 분유 뭐 먹이세요? 우리 애가 지금 먹는 분유에 배가 더부룩한 것 같아서 바꿔볼까 해요.', 41, 2, now() - interval '169 days'),
  ('a0000000-0000-0000-0000-000000000452', 'd0000000-0000-0000-0000-000000000016', 'general', NULL, '카페에서 아기가 조용하게 앉아있길래 뭐 하나 봤더니 휴지를 다 뜯고 있었어요 ㅋㅋ 창의력이라고 하겠습니다...', 11, 1, now() - interval '89 days'),
  ('a0000000-0000-0000-0000-000000000453', 'd0000000-0000-0000-0000-000000000067', 'region', NULL, '성남 산부인과 추천 부탁드려요. 첫 임신이라 병원 선택이 어려워요. 🏥', 49, 9, now() - interval '33 days'),
  ('a0000000-0000-0000-0000-000000000454', 'd0000000-0000-0000-0000-000000000099', 'qna', NULL, '산후조리원 2주 vs 4주 어떤 게 좋아요? 첫째라 경험이 없어서요.', 24, 14, now() - interval '17 days'),
  ('a0000000-0000-0000-0000-000000000455', 'd0000000-0000-0000-0000-000000000092', 'qna', NULL, '기저귀 사이즈 올리는 기준이 뭐예요? 등에서 샐 때가 있어요.', 43, 3, now() + interval '131 days'),
  ('a0000000-0000-0000-0000-000000000456', 'd0000000-0000-0000-0000-000000000008', 'birth_month', '2025-09', '2025-09 예정인데 여름 출산이라 땀띠 걱정... 여름 신생아 케어 팁 부탁해요!', 39, 6, now() - interval '66 days'),
  ('a0000000-0000-0000-0000-000000000457', 'd0000000-0000-0000-0000-000000000087', 'region', NULL, '수원 근처 아기랑 갈 만한 곳 있을까요? 유모차 접근성 좋은 곳이면 좋겠어요~', 17, 17, now() - interval '4 days'),
  ('a0000000-0000-0000-0000-000000000458', 'd0000000-0000-0000-0000-000000000061', 'general', NULL, '오늘 소아과에서 발달검사 했는데 "잘 크고 있어요"라는 말에 눈물이 핑... 맘들 다 잘하고 있는 거예요 💪', 61, 5, now() - interval '10 days'),
  ('a0000000-0000-0000-0000-000000000459', 'd0000000-0000-0000-0000-000000000092', 'region', NULL, '용인 키즈카페 추천! 넓고 깨끗하고 부모 쉴 공간도 있어요. 커피도 맛있고 ㅎㅎ', 29, 8, now() - interval '107 days'),
  ('a0000000-0000-0000-0000-000000000460', 'd0000000-0000-0000-0000-000000000010', 'birth_month', '2025-10', '2025-10생 아기 50일 됐어요! 방긋 웃기 시작했는데 세상 예뻐요. 사진 100장은 찍은 듯 ㅋㅋ', 10, 17, now() + interval '14 days'),
  ('a0000000-0000-0000-0000-000000000461', 'd0000000-0000-0000-0000-000000000067', 'qna', NULL, '임신 중 카페인 얼마까지 괜찮아요? 커피 한 잔도 안 되나요?', 64, 13, now() - interval '120 days'),
  ('a0000000-0000-0000-0000-000000000462', 'd0000000-0000-0000-0000-000000000037', 'region', NULL, '서울 이유식 배달 서비스 추천해주세요! 직접 만들기 힘들 때가 있어서요...', 22, 11, now() - interval '117 days'),
  ('a0000000-0000-0000-0000-000000000463', 'd0000000-0000-0000-0000-000000000026', 'general', NULL, '밤에 아기 재우고 남편이랑 같이 아기 사진 보면서 귀엽다고 난리치는 시간이 좋아요 ㅋㅋ', 53, 10, now() + interval '63 days'),
  ('a0000000-0000-0000-0000-000000000464', 'd0000000-0000-0000-0000-000000000048', 'birth_month', '2025-11', '2025-11생 아기 첫 걸음마 시작! 불안불안하게 3걸음 걸었어요. 넘어질 때마다 가슴이 철렁!', 34, 7, now() + interval '140 days'),
  ('a0000000-0000-0000-0000-000000000465', 'd0000000-0000-0000-0000-000000000001', 'qna', NULL, '아기가 밤에 열이 나요. 몇 도 이상이면 응급실 가야 하나요? 불안해요 😰', 4, 8, now() + interval '163 days'),
  ('a0000000-0000-0000-0000-000000000466', 'd0000000-0000-0000-0000-000000000089', 'qna', NULL, '첫째 있는데 둘째 임신했어요! 터울이 2년인데 첫째 질투가 걱정이에요.', 63, 11, now() - interval '169 days'),
  ('a0000000-0000-0000-0000-000000000467', 'd0000000-0000-0000-0000-000000000095', 'region', NULL, '천안 맘들 어디서 만나세요? 육아 수다 떨 친구가 필요해요 ㅋㅋ', 9, 7, now() + interval '61 days'),
  ('a0000000-0000-0000-0000-000000000468', 'd0000000-0000-0000-0000-000000000008', 'qna', NULL, '아기 코딱지 어떻게 빼나요? ㅋㅋ 면봉으로 하면 싫어하고... 코 흡입기 쓰시나요?', 12, 9, now() - interval '60 days'),
  ('a0000000-0000-0000-0000-000000000469', 'd0000000-0000-0000-0000-000000000067', 'birth_month', '2026-05', '2026-05생 아기 첫 이가 나왔어요! 아래 앞니인데 웃을 때 보이는 게 너무 귀여워요 😄', 60, 12, now() + interval '22 days'),
  ('a0000000-0000-0000-0000-000000000470', 'd0000000-0000-0000-0000-000000000065', 'general', NULL, '소아과 가서 성장 체크했는데 백분위 75% 나왔어요! 처음에 작게 태어나서 걱정했는데 쑥쑥 크고 있네요 💪', 55, 13, now() - interval '146 days'),
  ('a0000000-0000-0000-0000-000000000471', 'd0000000-0000-0000-0000-000000000056', 'region', NULL, '제주 아기 수영장 다니는 맘 계세요? 어떤 프로그램이 좋은지 궁금해요.', 11, 8, now() - interval '81 days'),
  ('a0000000-0000-0000-0000-000000000472', 'd0000000-0000-0000-0000-000000000041', 'birth_month', '2026-05', '2026-05생 아기 첫 이가 나왔어요! 아래 앞니인데 웃을 때 보이는 게 너무 귀여워요 😄', 17, 3, now() + interval '35 days'),
  ('a0000000-0000-0000-0000-000000000473', 'd0000000-0000-0000-0000-000000000020', 'general', NULL, '이유식 초기인데 아보카도 반응이 대박! 입 벌리고 기다려요 ㅋㅋ 아보카도가 이렇게 비싼데 아기는 모르겠지...', 31, 15, now() - interval '31 days'),
  ('a0000000-0000-0000-0000-000000000474', 'd0000000-0000-0000-0000-000000000046', 'qna', NULL, '임신 중 카페인 얼마까지 괜찮아요? 커피 한 잔도 안 되나요?', 16, 15, now() - interval '68 days'),
  ('a0000000-0000-0000-0000-000000000475', 'd0000000-0000-0000-0000-000000000016', 'general', NULL, '아기 첫 뒤집기 성공! 🎉 거실에서 나만 보고 있었는데 갑자기 되더라구요. 남편한테 영상 보여줬더니 자기도 보고 싶었다고 ㅠㅠ', 54, 22, now() - interval '179 days'),
  ('a0000000-0000-0000-0000-000000000476', 'd0000000-0000-0000-0000-000000000028', 'region', NULL, '창원 베이비 마사지 배울 수 있는 곳 아시나요? 아기 배 마사지 해주면 잠을 잘 잔다고 해서요.', 23, 5, now() - interval '64 days'),
  ('a0000000-0000-0000-0000-000000000477', 'd0000000-0000-0000-0000-000000000066', 'general', NULL, '이유식 시작했는데 쌀미음 첫 반응이 너무 웃겨요 ㅋㅋ 뭔가 인상을 찡그리면서도 계속 벌리는... 이유식 시작한 맘들 뭐부터 먹였어요?', 22, 9, now() + interval '45 days'),
  ('a0000000-0000-0000-0000-000000000478', 'd0000000-0000-0000-0000-000000000052', 'qna', NULL, '아기 땀띠가 심해요. 목이랑 겨드랑이에 발갛게 올라왔는데 어떻게 해요? 😥', 38, 18, now() - interval '119 days'),
  ('a0000000-0000-0000-0000-000000000479', 'd0000000-0000-0000-0000-000000000018', 'general', NULL, '아기 머리카락이 자라서 처음으로 묶었는데 핑크 머리끈 하고 너무 예뻐요!! 공주님이야 👸', 6, 8, now() - interval '103 days'),
  ('a0000000-0000-0000-0000-000000000480', 'd0000000-0000-0000-0000-000000000088', 'birth_month', '2025-09', '2025-09생 맘 여기 모여요~! 우리 아기들 다들 잘 자라고 있죠? 요즘 뭐가 달라졌는지 공유해요! 😊', 44, 3, now() + interval '67 days'),
  ('a0000000-0000-0000-0000-000000000481', 'd0000000-0000-0000-0000-000000000009', 'general', NULL, '모유수유 끊으려니 아기보다 제가 더 슬퍼요 ㅠㅠ 마지막 수유할 때 눈물이 주르륵...', 44, 15, now() + interval '24 days'),
  ('a0000000-0000-0000-0000-000000000482', 'd0000000-0000-0000-0000-000000000016', 'general', NULL, '아기가 혼자 서서 박수까지! 발달이 한 번에 오는 것 같아요. 어제까지 못 했는데 오늘 갑자기!', 32, 2, now() - interval '147 days'),
  ('a0000000-0000-0000-0000-000000000483', 'd0000000-0000-0000-0000-000000000093', 'general', NULL, '아기 첫 미술놀이 했는데 물감을 입에 넣으려 해서 난리났어요 ㅋㅋ 먹어도 되는 물감 사야겠어요', 4, 13, now() + interval '45 days'),
  ('a0000000-0000-0000-0000-000000000484', 'd0000000-0000-0000-0000-000000000028', 'qna', NULL, '모유수유 중인데 감기약 먹어도 되나요? 아기한테 영향 있을까 걱정이에요.', 20, 9, now() + interval '39 days'),
  ('a0000000-0000-0000-0000-000000000485', 'd0000000-0000-0000-0000-000000000079', 'birth_month', '2026-04', '2026-04생 아기 하이파이브 배웠어요! "하이~" 하면서 손뼉 치는데 세상 귀여워요 🤗', 18, 21, now() - interval '106 days'),
  ('a0000000-0000-0000-0000-000000000486', 'd0000000-0000-0000-0000-000000000008', 'general', NULL, '아기 100일 기념으로 가족사진 찍었는데 완성본 보고 눈물 났어요. 우리가 가족이 됐구나... 🥹', 27, 5, now() + interval '165 days'),
  ('a0000000-0000-0000-0000-000000000487', 'd0000000-0000-0000-0000-000000000032', 'birth_month', '2026-07', '2026-07생 예정맘인데 곧 만나네요! 출산가방 다 쌌는데 혹시 빠진 거 없는지 봐주세요 🥹', 54, 18, now() + interval '98 days'),
  ('a0000000-0000-0000-0000-000000000488', 'd0000000-0000-0000-0000-000000000062', 'birth_month', '2026-01', '2026-01생 아기 첫 기어다님 시작! 눈 깜짝할 사이에 부엌까지 도달해서 안전문 필수! 😂', 34, 12, now() + interval '129 days'),
  ('a0000000-0000-0000-0000-000000000489', 'd0000000-0000-0000-0000-000000000035', 'general', NULL, '소아과 가서 성장 체크했는데 백분위 75% 나왔어요! 처음에 작게 태어나서 걱정했는데 쑥쑥 크고 있네요 💪', 23, 20, now() - interval '72 days'),
  ('a0000000-0000-0000-0000-000000000490', 'd0000000-0000-0000-0000-000000000061', 'birth_month', '2025-09', '2025-09생 아기 50일 됐어요! 방긋 웃기 시작했는데 세상 예뻐요. 사진 100장은 찍은 듯 ㅋㅋ', 52, 19, now() + interval '41 days'),
  ('a0000000-0000-0000-0000-000000000491', 'd0000000-0000-0000-0000-000000000085', 'general', NULL, '아기 첫 돌 찍으러 스튜디오 갔는데 한복 입은 모습이 너무 사랑스러워요. 앨범 나오면 자랑할 거예요!', 37, 2, now() + interval '57 days'),
  ('a0000000-0000-0000-0000-000000000492', 'd0000000-0000-0000-0000-000000000046', 'qna', NULL, '태교 음악 뭐 들으세요? 클래식이 좋다고 하는데 저는 발라드가 더 편해요 🎵', 57, 6, now() - interval '152 days'),
  ('a0000000-0000-0000-0000-000000000493', 'd0000000-0000-0000-0000-000000000095', 'region', NULL, '창원 공원에서 소풍 모임 할 건데 참여할 맘? 도시락 각자 싸오고 아기들끼리 놀아요 🧺', 61, 19, now() - interval '180 days'),
  ('a0000000-0000-0000-0000-000000000494', 'd0000000-0000-0000-0000-000000000073', 'general', NULL, '첫째 재우고 둘째 먹이고... 투맘의 하루는 정신없지만 둘 다 잠든 밤이 제일 평화로워요 🌟', 63, 7, now() + interval '127 days'),
  ('a0000000-0000-0000-0000-000000000495', 'd0000000-0000-0000-0000-000000000040', 'general', NULL, '배란테스트기 두 줄 떴어요!! 긴장되지만 이번 달은 좋은 예감이 들어요 🙏', 5, 3, now() - interval '155 days'),
  ('a0000000-0000-0000-0000-000000000496', 'd0000000-0000-0000-0000-000000000003', 'birth_month', '2025-10', '2025-10생 맘들 아기 몸무게 어때요? 우리 8kg인데 큰 건지 작은 건지 궁금해요.', 3, 11, now() + interval '52 days'),
  ('a0000000-0000-0000-0000-000000000497', 'd0000000-0000-0000-0000-000000000092', 'general', NULL, '오늘 아기가 거울 보고 자기 모습에 깜짝 놀랐어요 ㅋㅋ 거울 속 아기한테 손도 뻗고 박치기도 하고...', 54, 11, now() - interval '38 days'),
  ('a0000000-0000-0000-0000-000000000498', 'd0000000-0000-0000-0000-000000000100', 'general', NULL, '아기가 기저귀 떼기 시작! 변기에 앉혀놓으면 뿌듯한 표정 짓는 게 ㅋㅋ 성공하면 박수 쳐줘요 👏', 36, 12, now() + interval '96 days'),
  ('a0000000-0000-0000-0000-000000000499', 'd0000000-0000-0000-0000-000000000076', 'general', NULL, '아기가 혼자 서서 박수까지! 발달이 한 번에 오는 것 같아요. 어제까지 못 했는데 오늘 갑자기!', 22, 11, now() - interval '41 days'),
  ('a0000000-0000-0000-0000-000000000500', 'd0000000-0000-0000-0000-000000000082', 'qna', NULL, '아기 두 돌인데 아직 말을 잘 못해요. 언어 치료 받아야 할까요? 걱정이에요 ㅠ', 44, 11, now() - interval '144 days')
